__device__ void horizontalStep (int *data,
                     const int count,
                     const int prevOffset,
                     const int midOffset,
                     const int nextOffset,
                     int flag,
                     int local_id,
                     int SIZE_X)
{
	const int STEPS = count / SIZE_X;
	const int finalCount = count % SIZE_X; 
    const int finalOffset = count - finalCount; 
	for(int i = 0; STEPS > i; i++)
	{
		const int previous = data[prevOffset + i * SIZE_X + local_id] ;
		const int next     = data[nextOffset + i * SIZE_X + local_id];
		int * center = & (data[midOffset + i *  SIZE_X + local_id]); 
		if (0 == flag)
		{
			*center -= (previous + next) /2; 
		} else if (1 == flag)
		{
			*center += (previous + next + 2) /4; 
		}
	}

	if(finalCount > local_id) {
        const int previous = data[prevOffset + finalOffset + local_id];
        const int next     = data[nextOffset + finalOffset + local_id];
        int * center = & (data[midOffset + finalOffset + local_id]);

        if (0 == flag)
		{
			*center -= (previous + next) /2; 
		} else if (1 == flag)
		{
			*center += (previous + next + 2) /4; 
		}
    }

}


__device__ void forEachHorizontalOdd(int *data,
