struct FDWT53Column
{
	bool CHECKED_LOADER;

	struct VerticalDWTPixelLoader loader;

    int offset;                   

    int pixel0, pixel1, pixel2;

};


__device__ void clear_FDWT53Column(struct FDWT53Column *st_FDWT53Column,
                        struct VerticalDWTPixelIO *pIO)
{
	st_FDWT53Column->offset = 0;
	st_FDWT53Column->pixel0 = 0;
	st_FDWT53Column->pixel1 = 0;
	st_FDWT53Column->pixel2 = 0;
	clear_PixelLoader(&(st_FDWT53Column->loader), pIO);
}


struct FDWT53 {
	int WIN_SIZE_X, WIN_SIZE_Y;
	struct FDWT53Column column;


    struct TransformBuffer buffer;


	int STRIDE;
};



__device__ int getColumnOffset(int columnIndex,
                    int * buffer) 
{
	columnIndex = columnIndex + (BOUNDARY_X);  
	return columnIndex / 2        
          + (columnIndex & 1) * buffer[buffer[7]];  // buffer[7] = ODD_OFFSET
}


__device__ void initColumn(int *fdwt53_buffer,
                struct FDWT53Column *column,
                bool CHECKED,
                const int * const input,
                const int sizeX,
                const int sizeY,
                const int colIndex,
                const int firstY,
                struct VerticalDWTPixelIO *pIO)
{	
	column->CHECKED_LOADER = CHECKED;
	column->offset = getColumnOffset(colIndex, fdwt53_buffer);

	const int firstX = blockIdx.x * fdwt53_buffer[0] + colIndex; // WIN_SIZE_X stored in buffer[0]
	if(0 == blockIdx.y) 
	{

		init_PixelLoader(&(column->loader), sizeX, sizeY, firstX, firstY, pIO, CHECKED);
		column->pixel2 = loadFrom(&(column->loader),input, pIO, CHECKED);  
        column->pixel1 = loadFrom(&(column->loader),input, pIO, CHECKED);  
        column->pixel0 = loadFrom(&(column->loader),input, pIO, CHECKED);  
		init_PixelLoader(&(column->loader), sizeX, sizeY, firstX, firstY + 1, pIO, CHECKED);
	} 
	else
	{
		init_PixelLoader(&(column->loader), sizeX, sizeY, firstX, firstY - 2, pIO, CHECKED);
		column->pixel0 = loadFrom(&(column->loader),input, pIO, CHECKED);  
        column->pixel1 = loadFrom(&(column->loader),input, pIO, CHECKED);  
        column->pixel2 = loadFrom(&(column->loader),input, pIO, CHECKED);  
	}

}


__device__ void loadAndVerticallyTransform (int *fdwt53_buffer,
                                 struct FDWT53Column *column,
                                 bool CHECKED,
                                 const int * const input,
                                 struct VerticalDWTPixelIO *pIO,
                                 int STRIDE,
                                 int WIN_SIZE_Y)
{
		fdwt53_buffer[column->offset + 0 * STRIDE] = column->pixel0;
		fdwt53_buffer[column->offset + 1 * STRIDE] = column->pixel1;
		fdwt53_buffer[column->offset + 2 * STRIDE] = column->pixel2;


	for (int i = 3; (3 + WIN_SIZE_Y) > i; i++) 
	{
		fdwt53_buffer[column->offset + i * STRIDE] = loadFrom(&(column->loader),input, pIO, CHECKED);

	} 


	column->pixel0 = fdwt53_buffer [column->offset + ( WIN_SIZE_Y + 0 ) * STRIDE] ;
	column->pixel1 = fdwt53_buffer [column->offset + ( WIN_SIZE_Y + 1 ) * STRIDE] ;
	column->pixel2 = fdwt53_buffer [column->offset + ( WIN_SIZE_Y + 2 ) * STRIDE] ;


	int flag = 0 ;
	forEachVerticalOdd (fdwt53_buffer, column->offset, flag, WIN_SIZE_Y + 3, STRIDE);
	flag = 1 ;
	forEachVerticalEven(fdwt53_buffer, column->offset, flag, WIN_SIZE_Y + 3, STRIDE);

}


__device__ void transform(int *fdwt53_buffer,
               bool CHECK_LOADS,
               bool CHECK_WRITES,
               const int * const in,
               int * out,
               const int sizeX,
               const int sizeY,
               const int winSteps,
               int WIN_SIZE_X,
               int WIN_SIZE_Y)
{ 		

	struct FDWT53Column column; column.CHECKED_LOADER = CHECK_LOADS; 
    struct VerticalDWTPixelIO pIO;
    struct FDWT53Column boundaryColumn; boundaryColumn.CHECKED_LOADER = CHECK_LOADS; 
    struct VerticalDWTPixelIO pIO_b;



	const int firstY = blockIdx.y * WIN_SIZE_Y * winSteps;
	initColumn(fdwt53_buffer, &column, CHECK_LOADS, in, sizeX, sizeY, threadIdx.x, firstY, &pIO); 



	clear_FDWT53Column(&boundaryColumn, &pIO_b);
	if (3 > threadIdx.x) {

	const int colId = threadIdx.x + ((0 == threadIdx.x) ? WIN_SIZE_X : -3);


	initColumn (fdwt53_buffer, &boundaryColumn, CHECK_LOADS, in, sizeX, sizeY, colId, firstY, &pIO_b);
	}


	const int outColumnIndex = (threadIdx.x * 2) - (WIN_SIZE_X - 1) * (threadIdx.x / ( WIN_SIZE_X / 2));


    const int outColumnOffset = getColumnOffset(outColumnIndex, fdwt53_buffer);


    const int outputFirstX = blockIdx.x * WIN_SIZE_X +outColumnIndex;  
	struct VerticalDWTBandWriter writer;  writer.CHECKED = CHECK_WRITES;
	struct VerticalDWTBandIO bandIO; bandIO.CHECKED = CHECK_WRITES;

	init_BandWriter(&writer, &bandIO, sizeX, sizeY, outputFirstX, firstY);





	for(int w = 0; winSteps > w; w++)
	{

		loadAndVerticallyTransform(fdwt53_buffer, &column, CHECK_LOADS, in, &pIO, fdwt53_buffer[8], WIN_SIZE_Y); 
		if (3 > threadIdx.x)
		{
			loadAndVerticallyTransform(fdwt53_buffer, &boundaryColumn, CHECK_LOADS, in, &pIO_b, fdwt53_buffer[8], WIN_SIZE_Y); 
		}

		__syncthreads(); 

		int flag = 0; 

		forEachHorizontalOdd(fdwt53_buffer, 2, WIN_SIZE_Y, flag, threadIdx.x, WIN_SIZE_X, fdwt53_buffer[8], fdwt53_buffer[7]);		
		__syncthreads();

		flag = 1;
		forEachHorizontalEven(fdwt53_buffer, 2, WIN_SIZE_Y, flag, threadIdx.x, WIN_SIZE_X, fdwt53_buffer[8], fdwt53_buffer[7]);		
 		__syncthreads();	


		for(int r = 2; (2+WIN_SIZE_Y) > r; r+= 2)
		{	
			writeLowInto(&writer,  &bandIO, out, &(fdwt53_buffer[outColumnOffset + r * fdwt53_buffer[8]]));
			writeHighInto(&writer, &bandIO, out, &(fdwt53_buffer[outColumnOffset + (r+1) * fdwt53_buffer[8]]));
		}

		__syncthreads();
	}

}



__device__ void Forward53Predict (const int p,
                       int * c,
                       const int n) 
{
		*c -= (p + n) /2;
}

__device__ void Forward53Update (const int p,
                      int * c,
                      const int n) 
{
		*c += (p + n + 2) /4;
}


__global__ void cl_fdwt53Kernel(const int * const in, 
                              int *  out, 
                              const int sx, 
                              const int sy, 
                              const int steps,
                              int WIN_SIZE_X,
                              int WIN_SIZE_Y)
{
	__shared__ int fdwt53_buffer[2182];
    // Initialize buffer
    for(int i = threadIdx.x; i < 2182; i += blockDim.x){
		fdwt53_buffer[i] = 0;
	}
	__syncthreads();

	fdwt53_buffer[0] = WIN_SIZE_X;
	fdwt53_buffer[1] = WIN_SIZE_Y + 3;
	fdwt53_buffer[8] = BOUNDARY_X + (WIN_SIZE_X / 2);
	fdwt53_buffer[6] = 32;  // SHM_BANKS
	fdwt53_buffer[7] = fdwt53_buffer[8] * fdwt53_buffer[1] + (fdwt53_buffer[6] - ((fdwt53_buffer[8] * fdwt53_buffer[1] + fdwt53_buffer[6] / 2) % fdwt53_buffer[6]));
	fdwt53_buffer[9] = fdwt53_buffer[8]; // STRIDE

	const int maxX = (blockIdx.x + 1) * WIN_SIZE_X + 1;
    const int maxY = (blockIdx.y + 1) * WIN_SIZE_Y * steps + 1;
    const bool atRightBoudary = sx <= maxX;
    const bool atBottomBoudary = sy <= maxY;



	if(atBottomBoudary)
	{

		transform(fdwt53_buffer, true, true, in, out, sx, sy, steps, WIN_SIZE_X, WIN_SIZE_Y);
	}
	else if(atRightBoudary)
	{

		transform(fdwt53_buffer, false, true, in, out, sx, sy, steps, WIN_SIZE_X, WIN_SIZE_Y);
	}
	else 
	{

		transform(fdwt53_buffer, false, false, in, out, sx, sy, steps, WIN_SIZE_X, WIN_SIZE_Y);
	}
}
